from prometheus_client import start_http_server, Counter, Summary
from flask import Flask, request
import hashlib

app = Flask(__name__)

# Summary to track request duration
REQUEST_TIME = Summary('request_processing_seconds', 'Time spent processing request')

# Counter to track requests with labels
REQUEST_COUNTER = Counter('http_requests_total', 'Total HTTP Requests',
                          ['user_id', 'session_id', 'hashed_path'])

def hash_path(path):
    return hashlib.md5(path.encode()).hexdigest()

@app.route('/<path:subpath>', methods=['GET', 'POST', 'PUT', 'DELETE'])
@REQUEST_TIME.time()
def track_request(subpath):
    user_id = request.args.get('user_id', 'unknown')
    session_id = request.args.get('session_id', 'unknown')
    hashed_path = hash_path(request.path)

    # Increment the counter with labels
    REQUEST_COUNTER.labels(user_id=user_id, session_id=session_id, hashed_path=hashed_path).inc()

    return "Request tracked", 200

if __name__ == '__main__':
    # Start Prometheus metrics server
    start_http_server(8000)
    # Start Flask application
    app.run(host='0.0.0.0', port=5000)